mapper.select:
SELECT cs.id AS clinic_session_id, cs.department_id, d.name AS department_name, cs.doctor_id, u.display_name AS doctor_name, cs.session_date, cs.period_code, cs.clinic_type, CAST(COUNT(slot.id) AS INTEGER) AS remaining_count, cs.fee FROM clinic_session cs JOIN departments d ON d.id = cs.department_id JOIN doctors doc ON doc.id = cs.doctor_id JOIN users u ON u.id = doc.user_id LEFT JOIN clinic_slot slot ON slot.session_id = cs.id AND slot.deleted_at IS NULL AND slot.slot_status = 'AVAILABLE' WHERE cs.deleted_at IS NULL AND d.deleted_at IS NULL AND doc.deleted_at IS NULL AND u.deleted_at IS NULL AND cs.session_status = 'OPEN'
AND cs.department_id = #{departmentId}
AND cs.session_date >= #{dateFrom}
AND cs.session_date <= #{dateTo}
GROUP BY cs.id, cs.department_id, d.name, cs.doctor_id, u.display_name, cs.session_date, cs.period_code, cs.clinic_type, cs.fee ORDER BY cs.session_date ASC, CASE cs.period_code WHEN 'MORNING' THEN 1 WHEN 'AFTERNOON' THEN 2 WHEN 'EVENING' THEN 3 ELSE 99 END ASC, cs.id ASC
